'use client';

import { RecentTransactions } from '@/components/dashboard/recent-transactions';
import { SummaryCard } from '@/components/dashboard/summary-card';
import { FeedbackCard } from '@/components/dashboard/feedback-card';
import { SpendingByCategoryChart } from '@/components/reports/spending-by-category-chart';
import { Wallet, TrendingUp, TrendingDown, Loader2 } from 'lucide-react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { useCollection, useFirestore, useUser, useMemoFirebase } from '@/firebase';
import { collection, query, orderBy } from 'firebase/firestore';
import { useMemo } from 'react';

export default function DashboardPage() {
  const { user, isUserLoading } = useUser();
  const firestore = useFirestore();

  const transactionsQuery = useMemoFirebase(() => {
    if (!firestore || !user) return null;
    return query(
      collection(firestore, 'users', user.uid, 'transactions'),
      orderBy('date', 'desc')
    );
  }, [firestore, user]);

  const { data: transactions, isLoading: isTransactionsLoading } = useCollection(transactionsQuery);

  const totals = useMemo(() => {
    if (!transactions) return { income: 0, expenses: 0, balance: 0 };
    
    const income = transactions
      .filter((t) => t.type === 'income')
      .reduce((acc, t) => acc + (t.amount || 0), 0);
    const expenses = transactions
      .filter((t) => t.type === 'expense')
      .reduce((acc, t) => acc + (t.amount || 0), 0);
    
    return {
      income,
      expenses,
      balance: income - expenses
    };
  }, [transactions]);

  if (isUserLoading || isTransactionsLoading) {
    return (
      <div className="flex h-[80vh] items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto w-full space-y-6">
      {/* Summary Row */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <SummaryCard
          title="Total Balance"
          value={totals.balance}
          icon={Wallet}
          variant="purple"
        />
        <SummaryCard
          title="Total Income"
          value={totals.income}
          icon={TrendingUp}
          variant="green"
        />
        <SummaryCard
          title="Total Expenses"
          value={totals.expenses}
          icon={TrendingDown}
          variant="red"
        />
      </div>

      {/* Transactions Row */}
      <RecentTransactions transactions={transactions || []} />

      {/* Bottom Row */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 pb-10">
        <Card className="shadow-md">
          <CardHeader className="py-4">
            <CardTitle className="text-lg font-bold text-[#1e293b]">Income vs Expenses Distribution</CardTitle>
          </CardHeader>
          <CardContent className="h-[400px] flex items-center justify-center p-0">
             <SpendingByCategoryChart transactions={transactions || []} />
          </CardContent>
        </Card>

        <FeedbackCard />
      </div>
    </div>
  );
}